    messages = [
        {"sender": "user", "message": "Confirmed, see you tomorrow at 6pm."},
        {"sender": "landlord", "message": "Can we reschedule? Thursday at 8pm works."}
    ]
    now = datetime.datetime(2026, 5, 19, 9, 0)  # Tuesday
    # Thursday is 21 May 2026
    expected = datetime.datetime(2026, 5, 21, 20, 0)
